var scores = {};
var naFlags = {};

function tid(ci, catI, ti) { return 'c' + ci + 'k' + catI + 't' + ti; }

function countAll() {
  var n = 0;
  DATA.forEach(function(c) { c.categories.forEach(function(cat) { n += cat.tasks.length; }); });
  return n;
}

function setScore(id, val) {
  if (scores[id] === val) {
    delete scores[id];
    val = 0;
  } else {
    scores[id] = val;
    delete naFlags[id];
  }
  renderButtons(id, val, false);
  updateSummary();
}

function toggleNA(id) {
  if (naFlags[id]) {
    delete naFlags[id];
    renderButtons(id, scores[id] || 0, false);
  } else {
    naFlags[id] = true;
    delete scores[id];
    renderButtons(id, 0, true);
  }
  updateSummary();
}

function renderButtons(id, activeVal, isNa) {
  var row = document.getElementById('row-' + id);
  if (!row) return;
  row.style.opacity = isNa ? '0.4' : '1';
  for (var i = 1; i <= 5; i++) {
    var btn = document.getElementById(id + '_s' + i);
    if (btn) {
      if (activeVal === i && !isNa) {
        btn.classList.add('selected');
      } else {
        btn.classList.remove('selected');
      }
    }
  }
  var naBtn = document.getElementById(id + '_na');
  if (naBtn) {
    if (isNa) { naBtn.classList.add('selected'); } else { naBtn.classList.remove('selected'); }
  }
}

function updateSummary() {
  var total = countAll();
  var naCount = 0;
  Object.keys(naFlags).forEach(function(k) { if (naFlags[k]) naCount++; });
  var scored = 0;
  var vals = [];
  Object.keys(scores).forEach(function(k) {
    if (scores[k] > 0 && !naFlags[k]) { scored++; vals.push(scores[k]); }
  });
  var sum = 0;
  vals.forEach(function(v) { sum += v; });
  var avg = vals.length ? (sum / vals.length).toFixed(1) : '--';
  var pct = total > 0 ? Math.round(((scored + naCount) / total) * 100) : 0;

  document.getElementById('totalTasks').textContent = total;
  document.getElementById('scoredCount').textContent = scored + (naCount ? ' + ' + naCount + ' N/A' : '');
  document.getElementById('avgScore').textContent = avg;

